const t={maxFlow:{intro:{t:0,b:{t:2,i:[{t:3}],s:"找出热端能够持续达到的最高体积流量（mm³/s）——通过逐步提高流量，同时监测挤出机的 StallGuard 负载，捕捉齿轮打滑的那一刻。请先预览测试方案；实时测试会加热并挤出料丝，因此运行前请先准备好打印机。"}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"帮助"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"关于 Max-Flow"}},close:{t:0,b:{t:2,i:[{t:3}],s:"关闭"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"使用方法"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"设置测试温度和料丝直径（选择一款热端可自动预填）。"}},{t:0,b:{t:2,i:[{t:3}],s:"预览测试方案——它会显示每个流量步进以及挤出多少料丝。"}},{t:0,b:{t:2,i:[{t:3}],s:"勾选安全检查清单，然后运行实时测试（加热 + 挤出）。"}},{t:0,b:{t:2,i:[{t:3}],s:"读取可持续的最大流量，并复制建议的切片软件数值。"}}],topics:{howItWorks:{title:{t:0,b:{t:2,i:[{t:3}],s:"测试原理"}},body:{t:0,b:{t:2,i:[{t:3}],s:"挤出机以稳步增加的体积流量推送料丝。当带齿驱动轮牢固咬合料丝时，StallGuard 负载读数保持平稳；一旦开始打滑，读数便会剧烈波动。在该波动出现之前所达到的最高流量，就是你可持续的最大流量。一旦检测到打滑，斜坡升流便会立即停止，因此不会在首次打滑之后继续磨削料丝。"}}},stallguard:{title:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard 打滑检测"}},body:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard 是 TMC 驱动器的一项功能，可报告电机负载。本测试在每个流量步进上对其进行多次采样，寻找离散度（IQR）或变异度（CV）的突然升高——这正是齿轮失去咬合的标志。阈值来自每款驱动器的专属配置。注意：在 TMC2209 挤出机上，本功能使用实验性的 SG4 路径，因此请把首次运行视为一次校准。"}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"安全须知"}},body:{t:0,b:{t:2,i:[{t:3}],s:"这是一项高温、运动的测试，会刻意让挤出机打滑。请装入料丝，确保喷嘴下方畅通（位于热床或废料区上方），并守在打印机旁。打印机正在打印时会拒绝运行，并且测试结束后加热器始终会被关闭。"}}},slicer:{title:{t:0,b:{t:2,i:[{t:3}],s:"使用测试结果"}},body:{t:0,b:{t:2,i:[{t:3}],s:"将建议数值填入切片软件的“max volumetric speed”（按料丝设置）。保守数值（实测最大值的 80%）是安全的日常上限；平衡数值（90%）则稍微更激进一些。提高热端温度通常能提升可达到的流量。"}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"术语表"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{flow:{term:{t:0,b:{t:2,i:[{t:3}],s:"体积流量"}},def:{t:0,b:{t:2,i:[{t:3}],s:"热端每秒熔化的塑料量（mm³/s）——快速打印真正的速度上限。"}}},stallguard:{term:{t:0,b:{t:2,i:[{t:3}],s:"StallGuard"}},def:{t:0,b:{t:2,i:[{t:3}],s:"TMC 驱动器的一种信号，用于报告电机的机械负载，本测试用它来感知挤出机打滑。"}}},slip:{term:{t:0,b:{t:2,i:[{t:3}],s:"打滑"}},def:{t:0,b:{t:2,i:[{t:3}],s:"当挤出机齿轮无法再以足够快的速度咬住料丝而出现空转时——即流量天花板。"}}},meltzone:{term:{t:0,b:{t:2,i:[{t:3}],s:"熔融区"}},def:{t:0,b:{t:2,i:[{t:3}],s:"热端被加热的那段长度；更长的熔融区（例如 Volcano）可支撑更高的流量。"}}}}},params:{title:{t:0,b:{t:2,i:[{t:3}],s:"测试参数"}},temperature:{t:0,b:{t:2,i:[{t:3}],s:"温度（°C）"}},filamentDiameter:{t:0,b:{t:2,i:[{t:3}],s:"料丝直径 Ø（mm）"}},hotend:{t:0,b:{t:2,i:[{t:3}],s:"热端（可选）"}},hotendNone:{t:0,b:{t:2,i:[{t:3}],s:"— 无 —"}},hotendHint:{t:0,b:{t:2,i:[{t:3,v:"预计约 "},{t:4,k:"flow"},{t:3,v:" mm³/s"}]}},startFlow:{t:0,b:{t:2,i:[{t:3}],s:"起始流量（mm³/s）"}},endFlow:{t:0,b:{t:2,i:[{t:3}],s:"结束流量（mm³/s）"}},stepFlow:{t:0,b:{t:2,i:[{t:3}],s:"步进（mm³/s）"}},samples:{t:0,b:{t:2,i:[{t:3}],s:"每步采样数"}},extrudePerStep:{t:0,b:{t:2,i:[{t:3}],s:"每步挤出量（mm）"}}},plan:{button:{t:0,b:{t:2,i:[{t:3}],s:"预览方案"}},title:{t:0,b:{t:2,i:[{t:3}],s:"计划的斜坡升流"}},stepCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" 步"}]}},totalExtrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm 料丝"}]}},sgField:{t:0,b:{t:2,i:[{t:3,v:"StallGuard 字段："},{t:4,k:"field"}]}},sgFieldUnknown:{t:0,b:{t:2,i:[{t:3}],s:"未知此驱动器的 StallGuard 字段"}},flowHead:{t:0,b:{t:2,i:[{t:3}],s:"流量（mm³/s）"}},feedrateHead:{t:0,b:{t:2,i:[{t:3}],s:"进给速率（mm/min）"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"实时测试会加热热端并挤出料丝，刻意一直到打滑为止。这里仅为预览——尚未运行任何操作。"}}},safety:{title:{t:0,b:{t:2,i:[{t:3}],s:"运行前——安全检查清单"}},items:[{t:0,b:{t:2,i:[{t:3}],s:"料丝已装入并能顺畅进料。"}},{t:0,b:{t:2,i:[{t:3}],s:"喷嘴下方畅通——位于热床或废料桶上方，而非悬空对着零件。"}},{t:0,b:{t:2,i:[{t:3}],s:"我接受本测试会刻意磨削/打滑一部分料丝。"}},{t:0,b:{t:2,i:[{t:3}],s:"整个测试过程我都会守在打印机旁。"}}],ack:{t:0,b:{t:2,i:[{t:3}],s:"上述事项我都已完成，打印机已准备就绪"}},note:{t:0,b:{t:2,i:[{t:3}],s:"打印过程中会拒绝运行；测试结束时会自动关闭加热器。"}}},run:{button:{t:0,b:{t:2,i:[{t:3}],s:"运行实时测试"}},running:{t:0,b:{t:2,i:[{t:3}],s:"运行中……（加热 + 挤出）"}},confirmTitle:{t:0,b:{t:2,i:[{t:3}],s:"开始实时 Max-Flow 测试？"}},confirmBody:{t:0,b:{t:2,i:[{t:3,v:"这会将热端加热到 "},{t:4,k:"temp"},{t:3,v:" °C，并挤出最多 "},{t:4,k:"mm"},{t:3,v:" mm 料丝，逐步升流直至挤出机打滑。"}]}},confirm:{t:0,b:{t:2,i:[{t:3}],s:"立即运行"}},cancel:{t:0,b:{t:2,i:[{t:3}],s:"取消"}},busy:{t:0,b:{t:2,i:[{t:3}],s:"已拒绝：打印机正忙（打印中或已暂停）。请在其空闲时重试。"}},error:{t:0,b:{t:2,i:[{t:3}],s:"测试失败。"}},noSg:{t:0,b:{t:2,i:[{t:3}],s:"未读取到任何 StallGuard 采样——打滑结果可能不可靠。该驱动器的实时 SG 字段可能需要针对此型号进行调整。"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"结果"}},maxFlow:{t:0,b:{t:2,i:[{t:3}],s:"可持续的最大流量"}},slipAt:{t:0,b:{t:2,i:[{t:3,v:"在 "},{t:4,k:"flow"},{t:3,v:" mm³/s 检测到打滑"}]}},noSlip:{t:0,b:{t:2,i:[{t:3}],s:"直到测试的最高流量都未出现打滑"}},reason:{t:0,b:{t:2,i:[{t:3}],s:"详情"}},recommendTitle:{t:0,b:{t:2,i:[{t:3}],s:"建议的切片软件数值（max volumetric speed）"}},conservative:{t:0,b:{t:2,i:[{t:3}],s:"保守（80%）"}},balanced:{t:0,b:{t:2,i:[{t:3}],s:"平衡（90%）"}},units:{t:0,b:{t:2,i:[{t:3}],s:"mm³/s"}}},states:{loadingHotends:{t:0,b:{t:2,i:[{t:3}],s:"正在加载热端……"}}}}};export{t as default};
